def _unquote_git_path(path: str) -> str:
    """Strip the C-style double-quoting git applies to paths containing
    spaces/special characters. A quoted path fails the ^research/... artifact
    regexes and would otherwise be silently skipped."""
    if len(path) >= 2 and path[0] == '"' and path[-1] == '"':
        try:
            path = (path[1:-1].encode("ascii", "backslashreplace")
                    .decode("unicode_escape").encode("latin-1").decode("utf-8"))
        except Exception:
            path = path[1:-1]
    return path


def _paths_from_porcelain_line(line: str) -> list:
    """Extract every path from one `git status --porcelain` line.

    Rename/copy lines ('R  old -> new') carry both names — enforce on each
    side (the old side no longer exists on disk and drops out harmlessly;
    the new side is the live artifact). Without this, the combined string
    matched the artifact regex but open() failed, so the hook exited 0
    silently — enforcement skipped, violating the never-silently-skip
    standard."""
    body = line[3:].strip()
    if ("R" in line[:2] or "C" in line[:2]) and " -> " in body:
        parts = body.split(" -> ", 1)
    else:
        parts = [body]
    return [_unquote_git_path(p) for p in parts]


