def added_lines_for(artifact_relpath: str, full_text: str) -> str:
    """Pattern-3 scope: lines ADDED in the same window the hook already
    enforces (working tree + staged vs HEAD, plus the HEAD commit).
    Artifacts not yet in HEAD count whole-file. Pre-patch prose debt is
    grandfathered — it never retro-blocks an unrelated edit."""
    try:
