    for args in (
        ["git", "-C", REPO_ROOT, "diff", "HEAD", "--", artifact_relpath],
        ["git", "-C", REPO_ROOT, "diff-tree", "--no-commit-id", "-p", "-r",
         "HEAD", "--", artifact_relpath],
